// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
#define MAXN 10000

// Function to perform DFS
void dfs(int u, int parent, int *depth, int **adj, int n) {
    depth[u] = (parent == -1) ? 0 : depth[parent] + 1;
    for (int i = 0; i < n; i++) {
        if (adj[u][i] == 1 && i != parent) {
            dfs(i, u, depth, adj, n);
        }
    }
}

// Function to calculate the importance of each city
void calculate_importance(int **M, int *importance, int n) {
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            importance[M[i][j]]++;
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int **adj = (int **)malloc(N * sizeof(int *));
        for (int i = 0; i < N; i++) {
            adj[i] = (int *)malloc(N * sizeof(int));
            for (int j = 0; j < N; j++) {
                adj[i][j] = 0;
            }
        }
        for (int i = 0; i < N - 1; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            u--;
            v--;
            adj[u][v] = adj[v][u] = 1;
        }
        int *depth = (int *)malloc(N * sizeof(int));
        dfs(0, -1, depth, adj, N);
        int **M = (int **)malloc(N * sizeof(int *));
        for (int i = 0; i < N; i++) {
            M[i] = (int *)malloc(N * sizeof(int));
        }
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                int u = i;
                int v = j;
                while (u != v) {
                    if (depth[u] > depth[v]) {
                        u = depth[u] - 1;
                    } else {
                        v = depth[v] - 1;
                    }
                }
                M[i][j] = u;
            }
        }
        int *importance = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            importance[i] = 0;
        }
        calculate_importance(M, importance, N);
        long long sum = 0;
        for (int i = 0; i < N; i++) {
            sum += (i + 1) * importance[i];
        }
        printf("%lld\n", sum % MOD);
        for (int i = 0; i < N; i++) {
            free(adj[i]);
            free(M[i]);
        }
        free(adj);
        free(M);
        free(depth);
        free(importance);
    }
    return 0;
}

